--
-- Table structure for table `publicaciones`
--

DROP TABLE IF EXISTS `publicaciones`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `publicaciones` (
  `id` int NOT NULL AUTO_INCREMENT,
  `medio_id` int NOT NULL,
  `marca_id` int DEFAULT NULL,
  `agencia_id` int DEFAULT NULL,
  `id_externo` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `campana` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `canal` enum('web','instagram_post','instagram_story','facebook','x','tiktok','youtube','threads') COLLATE utf8mb4_unicode_ci NOT NULL,
  `tipo` enum('articulo','post','story','reel','video','tweet') COLLATE utf8mb4_unicode_ci NOT NULL,
  `url` varchar(1000) COLLATE utf8mb4_unicode_ci NOT NULL,
  `titulo` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fecha_publicacion` datetime NOT NULL,
  `reach` int DEFAULT NULL,
  `likes` int DEFAULT NULL,
  `shares` int DEFAULT NULL,
  `comments` int DEFAULT NULL,
  `clicks` int DEFAULT NULL,
  `ga4_sessions` int DEFAULT NULL,
  `ga4_users` int DEFAULT NULL,
  `estado_metricas` enum('pendiente','actualizado','error','revisar','fijo','sin_datos') COLLATE utf8mb4_unicode_ci DEFAULT 'pendiente',
  `confianza_marca` int DEFAULT NULL,
  `ultima_actualizacion` datetime DEFAULT NULL,
  `captura_url` varchar(1000) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notas` text COLLATE utf8mb4_unicode_ci,
  `fecha_insercion` datetime DEFAULT NULL,
  `estado_marca` enum('estimated','to_review','ok') COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Estado de asignación de marca: estimated=auto>=80, to_review=revisar, ok=validado manualmente',
  PRIMARY KEY (`id`),
  KEY `ix_pub_estado` (`estado_metricas`),
  KEY `ix_pub_medio_fecha` (`medio_id`,`fecha_publicacion`),
  KEY `ix_pub_canal` (`canal`),
  KEY `ix_pub_agencia` (`agencia_id`),
  KEY `ix_pub_marca` (`marca_id`),
  CONSTRAINT `publicaciones_ibfk_1` FOREIGN KEY (`medio_id`) REFERENCES `medios` (`id`),
  CONSTRAINT `publicaciones_ibfk_2` FOREIGN KEY (`marca_id`) REFERENCES `marcas` (`id`),
  CONSTRAINT `publicaciones_ibfk_3` FOREIGN KEY (`agencia_id`) REFERENCES `agencias` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1445 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

